INSERT INTO `import_templates` (`deleted`, `created_on`, `modified_on`, `id`, `instructions`, `created_by`, `modified_by`, `object_id`) VALUES ('0', '2020-06-08 14:24:42.000000', '2020-06-08 14:24:42.000000', 'cafe33e3-348a-4088-8349-2aaa40b6aeee', '导入说明 ：###1. EXCEL中导入数据请放在sheet“指标”中\n###2. 请按所示列提供年月，岗位，医院编码，剂型编码，指标数量.\n###3. 导入模板上带*的字段是必填项目\n###4. 操作分为：新增、更新、删除，删除需要在Action列标记【D】；新增，更新无需标记，系统自动识别', '1', '1', '91d5ad4d-5bd2-4b2b-8997-eeb63713331a');
